import { useState, useEffect } from "react";
import { useSelector, useDispatch } from "react-redux";
import { toast } from "react-toastify";
import { login } from "../authReducer";

function Dashboard() {
  const [notifications, setNotifications] = useState([]);
  const [avatarFile, setAvatarFile] = useState(null);
  const user = useSelector((state) => state.auth.user);
  const dispatch = useDispatch();

  useEffect(() => {
    fetch(`http://localhost:3001/notifications?userId=${user.id}`)
      .then((res) => res.json())
      .then((data) => setNotifications(data))
      .catch((error) => toast.error("Ошибка загрузки уведомлений"));
  }, [user.id]);

  async function handleDelete(notificationId) {
    try {
      const response = await fetch(
        `http://localhost:3001/notifications/${notificationId}`,
        {
          method: "DELETE",
        }
      );
      if (response.ok) {
        setNotifications(
          notifications.filter((n) => n.id !== notificationId)
        );
        toast.success("Уведомление удалено!");
      } else {
        toast.error("Не удалось удалить уведомление");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при удалении уведомления");
    }
  }

  async function handleAvatarChange() {
    if (!avatarFile) {
      toast.error("Выберите файл!");
      return;
    }

    const allowedTypes = ["image/jpeg", "image/png"];
    const maxSize = 2 * 1024 * 1024;

    if (!allowedTypes.includes(avatarFile.type)) {
      toast.error("Допустимы только изображения (JPEG, PNG)");
      return;
    }

    if (avatarFile.size > maxSize) {
      toast.error("Файл слишком большой. Максимальный размер: 2 МБ");
      return;
    }

    const formData = new FormData();
    formData.append("file", avatarFile);
    try {
      const response = await fetch("http://localhost:3002/upload", {
        method: "POST",
        body: formData,
      });
      const data = await response.json();
      if (response.ok) {
        const updatedUser = { ...user, avatar: data.filePath };
        await fetch(`http://localhost:3001/users/${user.id}`, {
          method: "PATCH",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({ avatar: data.filePath }),
        });
        dispatch(login(updatedUser));
        await fetch("http://localhost:3001/notifications", {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            userId: user.id,
            message: "Ваш аватар обновлен.",
            createdAt: new Date().toISOString(),
          }),
        });
        toast.success("Аватар обновлен!");
      } else {
        toast.error("Не удалось загрузить аватар");
      }
    } catch (error) {
      toast.error("Сетевая ошибка при загрузке аватара");
    }
  }

  return (
    <div className="container mt-5">
      <h1 className="mb-4">Личный кабинет</h1>
      <div className="card mb-4">
        <div className="card-body">
          <h3>Профиль</h3>
          <div className="d-flex align-items-center mb-3">
            <img
              src={user.avatar || "/default-avatar.png"}
              alt="Avatar"
              className="rounded-circle me-3"
              style={{ width: "100px", height: "100px" }}
            />
            <div>
              <p><strong>Имя:</strong> {user.name}</p>
              <p><strong>Email:</strong> {user.email}</p>
              <p><strong>Роль:</strong> {user.role}</p>
              {user.classId && <p><strong>Класс:</strong> {user.classId}</p>}
            </div>
          </div>
          <div className="mb-3">
            <label htmlFor="avatar" className="form-label">
              Изменить аватар (JPEG, PNG, до 2 МБ)
            </label>
            <input
              type="file"
              id="avatar"
              className="form-control"
              onChange={(e) => setAvatarFile(e.target.files[0])}
            />
          </div>
          <button
            onClick={handleAvatarChange}
            className="btn btn-primary"
          >
            Обновить аватар
          </button>
        </div>
      </div>
      <h3>Уведомления</h3>
      {notifications.length === 0 ? (
        <p className="text-muted">Уведомлений нет.</p>
      ) : (
        <ul className="list-group">
          {notifications.map((notification) => (
            <li
              key={notification.id}
              className="list-group-item d-flex justify-content-between align-items-center"
            >
              <span>
                {notification.message}{" "}
                <small className="text-muted">
                  ({new Date(notification.createdAt).toLocaleString()})
                </small>
              </span>
              <button
                onClick={() => handleDelete(notification.id)}
                className="btn btn-danger btn-sm"
              >
                Удалить
              </button>
            </li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default Dashboard;
